**Optimization Strategy:**

1.  **`common_elements(a, b)`**: Use sets for efficient intersection finding.
2.  **`fib(n)`**: Implement the Fibonacci sequence using dynamic programming (memoization) to avoid redundant calculations.
3.  **`count_pairs(nums, target)`**: Utilize a hash map (dictionary) to count pairs efficiently.
4.  **`dedupe_keep_order(items)`**: Use a set to track seen elements while preserving order using a list.

**Implementation:**

```python
def common_elements(a, b):
    """Sorted list of values appearing in both lists."""
    set_a = set(a)
    set_b = set(b)
    common = sorted(list(set_a.intersection(set_b)))
    return common

def fib(n):
    """nth Fibonacci number (fib(0)=0, fib(1)=1)"""
    if n <= 1:
        return n
    memo = {}
    def fib_helper(n):
        if n in memo:
            return memo[n]
        if n <= 1:
            return n
        memo[n] = fib_helper(n-1) + fib_helper(n-2)
        return memo[n]
    return fib_helper(n)

def count_pairs(nums, target):
    """Number of index pairs i<j with nums[i]+nums[j] == target"""
    count = 0
    seen = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            count += seen[complement]
        if num in seen:
            seen[num] += 1
        else:
            seen[num] = 1
    return count

def dedupe_keep_order(items):
    """Remove duplicates, preserving first-seen order."""
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result
